require"UI.UIBase"require"UI.UIBlock"UI_Activity_Jiuji=UIBase:Inherit()local a=Basic.Enum{'none','get','noget','getted'}function UI_Activity_Jiuji:OnCreate()UI_Activity_Jiuji.Inst=self;self.activity_name=Tools.StrOfLocalization(2232)self.activity_id=3;self.has_gained=false;self.btn_cd=0 end;function UI_Activity_Jiuji:Init()LobbyNetMgr.SendRequest('Lobby','fetchReviveCoinInfo',ProtoMgr.CreateRequest('Lobby','fetchReviveCoinInfo'),function(b,c)self:makeReviveCoinInfo(c,b)end)LobbyNetMgr.AddMsgListener('NotifyReviveCoinUpdate',function(d)self.has_gained=d.has_gained end)end;function UI_Activity_Jiuji:makeReviveCoinInfo(c,b)if b or c.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='fetchReviveCoinInfo',error=b,res=c})else self.has_gained=c.has_gained end end;function UI_Activity_Jiuji:isopen()return true end;function UI_Activity_Jiuji:Show()self:Refresh()self.transform.gameObject:SetActive(true)end;function UI_Activity_Jiuji:Hide()self.transform.gameObject:SetActive(false)end;function UI_Activity_Jiuji:FindData()local e=0;local f=ExcelMgr.GetTable('events','soscoin')local g=Mathf.Max(GameMgr.Inst.account_data.level.id,GameMgr.Inst.account_data.level3.id-10000)if Tools.IsCelestial(g)then e=116 end;for h,i in pairs(f)do if i.level_limit==g then e=i.id end end;return e end;function UI_Activity_Jiuji:RefreshState(j)self.btn_get.gameObject:SetActive(j==a.get)self.btn_noget.gameObject:SetActive(j==a.noget)self.alreadyget.gameObject:SetActive(j==a.getted)end;function UI_Activity_Jiuji:ClickGet()if self.btn_cd>UnityEngine.Time.time then return end;self.btn_cd=UnityEngine.Time.time+1;LobbyNetMgr.SendRequest('Lobby','gainReviveCoin',ProtoMgr.CreateRequest('Lobby','gainReviveCoin'),function(b,c)self.btn_cd=0;if b or c.error.code~=0 then UIMgr.Inst:ShowUI(UI_ErrorInfo.className,nil,{errorType=UI_ErrorInfo.ErrorType.NetWork,method='gainReviveCoin',error=b,res=c})else self:RefreshState(a.getted)self.has_gained=true;if self.reward and#self.reward>0 then UIMgr.Inst:ShowUI(UI_GetReward.className,nil,{itemInfos=self.reward})end end end)end;function UI_Activity_Jiuji:Refresh()local k=ExcelMgr.GetData('events','soscoin',self:FindData())self.reward={}if k then self.desc.text=k['desc_'..GameMgr.Inst.prefer_language]if k.gold_num<1 then self.task.transform.gameObject:SetActive(false)self.empty.transform.gameObject:SetActive(true)self.text_desc_empty.text=k['desc_'..GameMgr.Inst.prefer_language]else self.task.transform.gameObject:SetActive(true)self.empty.transform.gameObject:SetActive(false)self.item_count.text=k.gold_num;if self.has_gained then self:RefreshState(a.getted)elseif GameMgr.Inst.account_data.gold<k.gold_limit then self:RefreshState(a.get)else self:RefreshState(a.noget)end;local l=ExcelMgr.GetData('item_definition','currency',100002)self.item_name.text=l['name_'..GameMgr.Inst.prefer_language]self.reward={{id=100002,num=k.gold_num,count=k.gold_num}}end else self.text_desc_empty.text=Tools.StrOfLocalization(2233)self.task.transform.gameObject:SetActive(false)self.empty.transform.gameObject:SetActive(true)end end;function UI_Activity_Jiuji:haveRedPoint()return false end;function UI_Activity_Jiuji:need_popout()return false end;return UI_Activity_Jiuji